parameters.functionCode:
// Validate + normalize the payload posted by the NetSuite User Event
// script (see docs/netsuite-integration.md). Kong has already enforced
// key-auth and stripped the X-API-Key header (hide_credentials=true), so
// we do NOT re-validate the key here. We DO validate the payload shape so
// a malformed push doesn't pollute Kafka.
const body = $input.item.json;

const required = ['source', 'event_type', 'record_type', 'id'];
for (const f of required) {
  if (!body[f]) {
    const err = new Error(`missing required field: ${f}`);
    err.statusCode = 400;
    throw err;
  }
}
if (body.source !== 'netsuite') {
  const err = new Error(`unexpected source: ${body.source}`);
  err.statusCode = 400;
  throw err;
}

// Route by record type. Sales orders flow into the main orders topic so
// downstream consumers (WMS, Unigroup booking, dispatch) can subscribe
// without caring about the origin system. Inventory-adjacent types share
// the inventory topic. Everything else lands on netsuite-updates as a
// generic change feed.
const TYPE_ROUTING = {
  salesorder:          'orders',
  inventoryadjustment: 'inventory',
  itemreceipt:         'inventory',
  itemfulfillment:     'inventory'
};
const topic = TYPE_ROUTING[body.record_type] || 'netsuite-updates';

const event = {
  source:      'netsuite',
  event_type:  body.event_type,       // 'create' | 'edit'
  record_type: body.record_type,
  id:          String(body.id),
  tran_id:     body.tran_id || null,
  entity:      body.entity || null,
  total:       body.total || null,
  status:      body.status || null,
  timestamp:   body.timestamp || new Date().toISOString(),
  received_at: new Date().toISOString(),
  correlation_id: $('NetSuite Webhook').first().json.headers?.['x-request-id'] || $execution.id,
  // Partition key - keep ordering per-record across edits
  _key: `netsuite:${body.record_type}:${body.id}`,
  _topic: topic
};

return { json: event };

// Decide whether this was a client error (400 - bad payload) or a server
// error (500 - Kafka unreachable etc.). statusCode set by Validate + Route
// survives onto the error item; anything without it is 500.
const err = $input.item.json;
const status = err.statusCode || err.status || 500;
const isClient = status >= 400 && status < 500;

return {
  json: {
    workflow: 'netsuite-webhook-to-kafka',
    error:    err.message || err.error || 'unknown',
    status,
    is_client_error: isClient,
    original: err,
    timestamp: new Date().toISOString()
  }
};
